export const allRexPnPages: RexPnPage[] = [
  ...categoryPages,
  ...conditionPages,
  ...labValuePages,
  ...medicationPages,
  ...comparisonPages,
  ...strategyPages,
  ...questionBankPages,
];

export function getRexPnPageBySlug(slug: string): RexPnPage | undefined {
  return allRexPnPages.find(p => p.slug === slug);
}

export function getRexPnPagesByType(type: RexPnPageType): RexPnPage[] {
  return allRexPnPages.filter(p => p.type === type);
}

export function getPathPrefix(page: RexPnPage): string {
  switch (page.type) {
    case "condition": return "/rex-pn/conditions";
    case "lab-value": return "/rex-pn/labs";
    case "medication": return "/rex-pn/medications";
    case "comparison": return "/rex-pn/comparisons";
    case "strategy":
    case "question-bank":
    case "category":
    default: return "/rex-pn";
  }
}

export function getFullPath(page: RexPnPage): string {
  return `${getPathPrefix(page)}/${page.slug}`;
}

export function getAllRexPnPaths(): string[] {
  return allRexPnPages.map(p => getFullPath(p));
}
